namespace ProductsApi.Models;

public enum Category
{
    Electronics,
    Clothing,
    Food,
    Books
}

public class Product
{
    public Guid Id { get; set; }
    public required string Name { get; set; }
    public decimal Price { get; set; }
    public Category Category { get; set; }
    public DateTime CreatedAt { get; set; }
}

public class CreateProductRequest
{
    public required string Name { get; set; }
    public decimal Price { get; set; }
    public Category Category { get; set; }
}

using ProductsApi.Models;

namespace ProductsApi.Services;

public interface IProductService
{
    IReadOnlyList<Product> GetAll();
    Product? GetById(Guid id);
    Product Create(CreateProductRequest request);
}

using System.Collections.Concurrent;
using ProductsApi.Models;

namespace ProductsApi.Services;

public class InMemoryProductService : IProductService
{
    private readonly ConcurrentDictionary<Guid, Product> _products = new();

    public IReadOnlyList<Product> GetAll()
    {
        return _products.Values.OrderBy(p => p.CreatedAt).ToList();
    }

    public Product? GetById(Guid id)
    {
        _products.TryGetValue(id, out var product);
        return product;
    }

    public Product Create(CreateProductRequest request)
    {
        var product = new Product
        {
            Id = Guid.NewGuid(),
            Name = request.Name,
            Price = request.Price,
            Category = request.Category,
            CreatedAt = DateTime.UtcNow
        };

        _products[product.Id] = product;
        return product;
    }
}

using Microsoft.AspNetCore.Http.HttpResults;
using Microsoft.AspNetCore.Mvc;
using ProductsApi.Models;
using ProductsApi.Services;

namespace ProductsApi.Controllers;

[ApiController]
[Route("api/[controller]")]
[Produces("application/json")]
public class ProductsController(IProductService productService) : ControllerBase
{
    /// <summary>
    /// Retrieves all products.
    /// </summary>
    /// <returns>A list of all products ordered by creation date.</returns>
    /// <response code="200">Returns the list of products.</response>
    [HttpGet]
    [EndpointSummary("List all products")]
    [EndpointDescription("Retrieves every product in the catalog, ordered by creation date ascending.")]
    [ProducesResponseType<IReadOnlyList<Product>>(StatusCodes.Status200OK)]
    public IResult GetAll()
    {
        var products = productService.GetAll();
        return TypedResults.Ok(products);
    }

    /// <summary>
    /// Retrieves a product by its unique identifier.
    /// </summary>
    /// <param name="id">The unique identifier of the product.</param>
    /// <returns>The product if found.</returns>
    /// <response code="200">Returns the requested product.</response>
    /// <response code="404">Product with the specified ID was not found.</response>
    [HttpGet("{id:guid}")]
    [EndpointSummary("Get a product by ID")]
    [EndpointDescription("Retrieves a single product by its unique GUID identifier.")]
    [ProducesResponseType<Product>(StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    public IResult GetById(Guid id)
    {
        var product = productService.GetById(id);
        return product is null
            ? TypedResults.NotFound()
            : TypedResults.Ok(product);
    }

    /// <summary>
    /// Creates a new product.
    /// </summary>
    /// <param name="request">The product data to create.</param>
    /// <returns>The newly created product.</returns>
    /// <response code="201">Product created successfully.</response>
    [HttpPost]
    [EndpointSummary("Create a new product")]
    [EndpointDescription("Creates a new product with an auto-generated ID and timestamp. Returns the created product with a Location header.")]
    [ProducesResponseType<Product>(StatusCodes.Status201Created)]
    public IResult Create([FromBody] CreateProductRequest request)
    {
        var product = productService.Create(request);
        return TypedResults.Created($"/api/products/{product.Id}", product);
    }
}

